import csv
import sys
from collections import Counter, defaultdict
from pathlib import Path

def try_parse_number(value):
    if value is None:
        return None
    text = str(value).strip()
    if text == "":
        return None
    try:
        if "." in text:
            return float(text)
        return int(text)
    except ValueError:
        return None

def summarize_csv(file_path):
    path = Path(file_path)
    if not path.exists():
        raise FileNotFoundError(f"File not found: {file_path}")

    with path.open("r", newline="", encoding="utf-8-sig") as f:
        reader = csv.DictReader(f)
        rows = list(reader)
        headers = reader.fieldnames or []

    summary = {
        "file": str(path),
        "row_count": len(rows),
        "column_count": len(headers),
        "columns": {}
    }

    for header in headers:
        values = [row.get(header, "") for row in rows]
        non_empty = [v for v in values if str(v).strip() != ""]
        numeric_values = []

        for v in non_empty:
            parsed = try_parse_number(v)
            if parsed is not None:
                numeric_values.append(parsed)

        column_summary = {
            "non_empty_count": len(non_empty),
            "empty_count": len(values) - len(non_empty),
            "unique_count": len(set(non_empty)),
        }

        if non_empty:
            most_common = Counter(non_empty).most_common(5)
            column_summary["top_values"] = most_common

        if len(numeric_values) == len(non_empty) and numeric_values:
            column_summary["type"] = "numeric"
            column_summary["min"] = min(numeric_values)
            column_summary["max"] = max(numeric_values)
            column_summary["sum"] = sum(numeric_values)
            column_summary["avg"] = sum(numeric_values) / len(numeric_values)
        else:
            column_summary["type"] = "text"

        summary["columns"][header] = column_summary

    return summary

def print_summary(summary):
    print(f"File: {summary['file']}")
    print(f"Rows: {summary['row_count']}")
    print(f"Columns: {summary['column_count']}")
    print()

    for column, info in summary["columns"].items():
        print(f"Column: {column}")
        print(f"  Type: {info['type']}")
        print(f"  Non-empty: {info['non_empty_count']}")
        print(f"  Empty: {info['empty_count']}")
        print(f"  Unique: {info['unique_count']}")

        if "top_values" in info:
            print("  Top values:")
            for value, count in info["top_values"]:
                print(f"    {value}: {count}")

        if info["type"] == "numeric":
            print(f"  Min: {info['min']}")
            print(f"  Max: {info['max']}")
            print(f"  Sum: {info['sum']}")
            print(f"  Avg: {info['avg']:.2f}")

        print()

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python summarize_csv.py <file.csv>")
        sys.exit(1)

    csv_file = sys.argv[1]
    result = summarize_csv(csv_file)
    print_summary(result)
